const BRAND_GOLD = '#D4AF37';

/**
 * Get a translated email string with placeholder replacement.
 * Falls back to English if locale or key not found.
 */
export function getEmailString(locale: string, key: string, vars?: Record<string, string>): string {
    const lang = EMAIL_STRINGS[locale] || EMAIL_STRINGS['en'];
    let str = lang[key] || EMAIL_STRINGS['en'][key] || key;
    if (vars) {
        for (const [k, v] of Object.entries(vars)) {
            str = str.replace(new RegExp(`\\{${k}\\}`, 'g'), v);
        }
    }
    // Always replace {gold} with brand color
    str = str.replace(/\{gold\}/g, BRAND_GOLD);
    return str;
}
